//! bootstrap-image-sources -- fold canonical/local rendered images into a next seed.
//!
//! The operator is intentionally deterministic and model-free:
//! - equal-size canonical/local images are loaded as RGBA8
//! - pixels whose max channel delta exceeds `--threshold` are averaged
//! - non-divergent pixels keep the canonical source
//! - a grayscale divergence map and JSON manifest make the fold auditable

use std::path::{Path, PathBuf};
use std::process::ExitCode;

use image::{GrayImage, RgbaImage};
use serde_json::json;

#[derive(Clone, Debug)]
struct Cli {
    canonical: Option<PathBuf>,
    local: Option<PathBuf>,
    output: Option<PathBuf>,
    divergence: Option<PathBuf>,
    manifest: Option<PathBuf>,
    threshold: f32,
    round: u32,
    self_test: Option<PathBuf>,
}

#[derive(Clone, Debug)]
struct FoldStats {
    width: u32,
    height: u32,
    pixels: u64,
    threshold: f32,
    divergent_pixels: u64,
    mean_abs_delta: f64,
    rms_delta: f64,
    max_abs_delta: f32,
    bootstrap_mean_abs_from_canonical: f64,
}

#[derive(Clone, Debug)]
struct FoldResult {
    bootstrap: RgbaImage,
    divergence: GrayImage,
    stats: FoldStats,
}

fn main() -> ExitCode {
    match real_main() {
        Ok(()) => ExitCode::SUCCESS,
        Err(error) => {
            eprintln!("bootstrap-image-sources: {error}");
            ExitCode::FAILURE
        }
    }
}

fn real_main() -> Result<(), String> {
    let cli = parse_cli(std::env::args().skip(1))?;
    if let Some(dir) = cli.self_test.as_deref() {
        return run_self_test(dir);
    }

    let canonical_path = cli
        .canonical
        .as_deref()
        .ok_or_else(|| "missing --canonical".to_string())?;
    let local_path = cli
        .local
        .as_deref()
        .ok_or_else(|| "missing --local".to_string())?;
    let output_path = cli
        .output
        .as_deref()
        .ok_or_else(|| "missing --output".to_string())?;

    let canonical = load_rgba(canonical_path)?;
    let local = load_rgba(local_path)?;
    let result = fold_sources(&canonical, &local, cli.threshold)?;

    save_rgba(output_path, &result.bootstrap)?;
    if let Some(path) = cli.divergence.as_deref() {
        save_gray(path, &result.divergence)?;
    }
    if let Some(path) = cli.manifest.as_deref() {
        write_manifest(
            path,
            canonical_path,
            local_path,
            output_path,
            cli.divergence.as_deref(),
            &result.stats,
            cli.round,
        )?;
    }

    println!(
        "round={},pixels={},divergent_pixels={},divergent_ratio={:.9},rms_delta={:.9},max_abs_delta={:.9},output={}",
        cli.round,
        result.stats.pixels,
        result.stats.divergent_pixels,
        divergent_ratio(&result.stats),
        result.stats.rms_delta,
        result.stats.max_abs_delta,
        output_path.display()
    );
    Ok(())
}

fn parse_cli<I>(args: I) -> Result<Cli, String>
where
    I: IntoIterator<Item = String>,
{
    let mut cli = Cli {
        canonical: None,
        local: None,
        output: None,
        divergence: None,
        manifest: None,
        threshold: 0.0,
        round: 0,
        self_test: None,
    };

    let mut iter = args.into_iter();
    while let Some(arg) = iter.next() {
        match arg.as_str() {
            "--canonical" => {
                cli.canonical = Some(PathBuf::from(required(&mut iter, "--canonical")?))
            }
            "--local" => cli.local = Some(PathBuf::from(required(&mut iter, "--local")?)),
            "--output" => cli.output = Some(PathBuf::from(required(&mut iter, "--output")?)),
            "--divergence" => {
                cli.divergence = Some(PathBuf::from(required(&mut iter, "--divergence")?))
            }
            "--manifest" => cli.manifest = Some(PathBuf::from(required(&mut iter, "--manifest")?)),
            "--threshold" => {
                cli.threshold = parse_threshold(&required(&mut iter, "--threshold")?)?;
            }
            "--round" => {
                cli.round = required(&mut iter, "--round")?
                    .parse()
                    .map_err(|error| format!("--round: {error}"))?;
            }
            "--self-test" => {
                cli.self_test = Some(PathBuf::from(required(&mut iter, "--self-test")?));
            }
            "-h" | "--help" => {
                print_usage();
                std::process::exit(0);
            }
            other => return Err(format!("unknown argument {other:?}")),
        }
    }

    if cli.self_test.is_none()
        && (cli.canonical.is_none() || cli.local.is_none() || cli.output.is_none()) {
            return Err("usage: bootstrap-image-sources --canonical C.png --local L.png --output bootstrap.png [--divergence heat.png] [--manifest fold.json] [--threshold 0..1] [--round N]".to_string());
        }
    Ok(cli)
}

fn required<I>(iter: &mut I, name: &str) -> Result<String, String>
where
    I: Iterator<Item = String>,
{
    iter.next()
        .ok_or_else(|| format!("{name} requires a value"))
}

fn parse_threshold(raw: &str) -> Result<f32, String> {
    let value: f32 = raw
        .parse()
        .map_err(|error| format!("--threshold: {error}"))?;
    if !value.is_finite() || !(0.0..=1.0).contains(&value) {
        return Err("--threshold must be finite and in [0, 1]".to_string());
    }
    Ok(value)
}

fn print_usage() {
    eprintln!(
        "usage: bootstrap-image-sources --canonical C.png --local L.png --output bootstrap.png \\
         [--divergence heat.png] [--manifest fold.json] [--threshold 0..1] [--round N]\n\
         bootstrap-image-sources --self-test OUT_DIR"
    );
}

fn load_rgba(path: &Path) -> Result<RgbaImage, String> {
    image::open(path)
        .map_err(|error| format!("open {}: {error}", path.display()))
        .map(|image| image.to_rgba8())
}

fn save_rgba(path: &Path, image: &RgbaImage) -> Result<(), String> {
    ensure_parent(path)?;
    image
        .save(path)
        .map_err(|error| format!("save {}: {error}", path.display()))
}

fn save_gray(path: &Path, image: &GrayImage) -> Result<(), String> {
    ensure_parent(path)?;
    image
        .save(path)
        .map_err(|error| format!("save {}: {error}", path.display()))
}

fn ensure_parent(path: &Path) -> Result<(), String> {
    if let Some(parent) = path.parent() {
        if !parent.as_os_str().is_empty() {
            std::fs::create_dir_all(parent)
                .map_err(|error| format!("create {}: {error}", parent.display()))?;
        }
    }
    Ok(())
}

fn fold_sources(
    canonical: &RgbaImage,
    local: &RgbaImage,
    threshold: f32,
) -> Result<FoldResult, String> {
    if canonical.dimensions() != local.dimensions() {
        return Err(format!(
            "dimension mismatch: canonical={}x{}, local={}x{}",
            canonical.width(),
            canonical.height(),
            local.width(),
            local.height()
        ));
    }

    let width = canonical.width();
    let height = canonical.height();
    let pixels = u64::from(width) * u64::from(height);
    let threshold_u8 = threshold * 255.0;
    let canonical_raw = canonical.as_raw();
    let local_raw = local.as_raw();
    let mut bootstrap = vec![0u8; canonical_raw.len()];
    let mut divergence = vec![0u8; pixels as usize];
    let mut divergent_pixels = 0u64;
    let mut total_abs_delta = 0.0f64;
    let mut total_sq_delta = 0.0f64;
    let mut max_abs_delta = 0u8;
    let mut bootstrap_abs_from_canonical = 0.0f64;

    for pixel_index in 0..pixels as usize {
        let offset = pixel_index * 4;
        let mut pixel_max_delta = 0u8;
        let mut averaged = [0u8; 4];

        for channel in 0..4 {
            let c = canonical_raw[offset + channel];
            let l = local_raw[offset + channel];
            let delta = c.abs_diff(l);
            let normalized = f64::from(delta) / 255.0;
            total_abs_delta += normalized;
            total_sq_delta += normalized * normalized;
            max_abs_delta = max_abs_delta.max(delta);
            pixel_max_delta = pixel_max_delta.max(delta);
            averaged[channel] = (u16::from(c) + u16::from(l)).div_ceil(2) as u8;
        }

        if f32::from(pixel_max_delta) > threshold_u8 {
            divergent_pixels += 1;
            bootstrap[offset..offset + 4].copy_from_slice(&averaged);
            for channel in 0..4 {
                bootstrap_abs_from_canonical +=
                    f64::from(canonical_raw[offset + channel].abs_diff(averaged[channel])) / 255.0;
            }
            divergence[pixel_index] = pixel_max_delta;
        } else {
            bootstrap[offset..offset + 4].copy_from_slice(&canonical_raw[offset..offset + 4]);
        }
    }

    let channels = pixels as f64 * 4.0;
    let bootstrap_image = RgbaImage::from_raw(width, height, bootstrap)
        .ok_or_else(|| "failed to construct bootstrap image".to_string())?;
    let divergence_image = GrayImage::from_raw(width, height, divergence)
        .ok_or_else(|| "failed to construct divergence image".to_string())?;
    let stats = FoldStats {
        width,
        height,
        pixels,
        threshold,
        divergent_pixels,
        mean_abs_delta: total_abs_delta / channels,
        rms_delta: (total_sq_delta / channels).sqrt(),
        max_abs_delta: f32::from(max_abs_delta) / 255.0,
        bootstrap_mean_abs_from_canonical: bootstrap_abs_from_canonical / channels,
    };

    Ok(FoldResult {
        bootstrap: bootstrap_image,
        divergence: divergence_image,
        stats,
    })
}

fn write_manifest(
    path: &Path,
    canonical: &Path,
    local: &Path,
    output: &Path,
    divergence: Option<&Path>,
    stats: &FoldStats,
    round: u32,
) -> Result<(), String> {
    ensure_parent(path)?;
    let manifest = json!({
        "tool": "bootstrap-image-sources",
        "policy": "divergence-gated-average",
        "round": round,
        "inputs": {
            "canonical": canonical,
            "local": local
        },
        "outputs": {
            "bootstrap": output,
            "divergence": divergence
        },
        "image": {
            "width": stats.width,
            "height": stats.height,
            "channels": "rgba8",
            "pixels": stats.pixels
        },
        "divergence": {
            "threshold": stats.threshold,
            "divergent_pixels": stats.divergent_pixels,
            "divergent_ratio": divergent_ratio(stats),
            "mean_abs_delta": stats.mean_abs_delta,
            "rms_delta": stats.rms_delta,
            "max_abs_delta": stats.max_abs_delta
        },
        "bootstrap": {
            "mean_abs_delta_from_canonical": stats.bootstrap_mean_abs_from_canonical,
            "next_round": "Use the bootstrap image as the next generation seed, then fold the next canonical/local pair with the same policy."
        }
    });
    let bytes = serde_json::to_vec_pretty(&manifest).map_err(|error| error.to_string())?;
    std::fs::write(path, bytes).map_err(|error| format!("write {}: {error}", path.display()))
}

fn divergent_ratio(stats: &FoldStats) -> f64 {
    if stats.pixels == 0 {
        0.0
    } else {
        stats.divergent_pixels as f64 / stats.pixels as f64
    }
}

fn run_self_test(dir: &Path) -> Result<(), String> {
    std::fs::create_dir_all(dir).map_err(|error| format!("create {}: {error}", dir.display()))?;
    let canonical_path = dir.join("canonical.png");
    let local_path = dir.join("local.png");
    let output_path = dir.join("bootstrap.png");
    let divergence_path = dir.join("divergence.png");
    let manifest_path = dir.join("manifest.json");

    let canonical = RgbaImage::from_raw(
        2,
        2,
        vec![
            10, 20, 30, 255, 40, 50, 60, 255, 70, 80, 90, 255, 100, 110, 120, 255,
        ],
    )
    .ok_or_else(|| "self-test canonical image construction failed".to_string())?;
    let local = RgbaImage::from_raw(
        2,
        2,
        vec![
            10, 20, 30, 255, 50, 70, 90, 255, 70, 80, 90, 255, 120, 110, 100, 255,
        ],
    )
    .ok_or_else(|| "self-test local image construction failed".to_string())?;

    save_rgba(&canonical_path, &canonical)?;
    save_rgba(&local_path, &local)?;
    let result = fold_sources(&canonical, &local, 0.0)?;
    if result.stats.divergent_pixels != 2 {
        return Err(format!(
            "self-test divergent pixel count mismatch: {}",
            result.stats.divergent_pixels
        ));
    }
    let expected = [
        10, 20, 30, 255, 45, 60, 75, 255, 70, 80, 90, 255, 110, 110, 110, 255,
    ];
    if result.bootstrap.as_raw().as_slice() != expected {
        return Err("self-test bootstrap image mismatch".to_string());
    }

    save_rgba(&output_path, &result.bootstrap)?;
    save_gray(&divergence_path, &result.divergence)?;
    write_manifest(
        &manifest_path,
        &canonical_path,
        &local_path,
        &output_path,
        Some(&divergence_path),
        &result.stats,
        0,
    )?;
    println!(
        "self_test=ok,dir={},bootstrap={},manifest={}",
        dir.display(),
        output_path.display(),
        manifest_path.display()
    );
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn equal_images_have_zero_divergence() {
        let image = RgbaImage::from_raw(1, 1, vec![1, 2, 3, 255]).unwrap();
        let result = fold_sources(&image, &image, 0.0).unwrap();
        assert_eq!(result.stats.divergent_pixels, 0);
        assert_eq!(result.stats.max_abs_delta, 0.0);
        assert_eq!(result.bootstrap.as_raw(), image.as_raw());
    }

    #[test]
    fn divergent_pixels_are_averaged() {
        let canonical = RgbaImage::from_raw(1, 1, vec![10, 20, 30, 255]).unwrap();
        let local = RgbaImage::from_raw(1, 1, vec![20, 40, 60, 255]).unwrap();
        let result = fold_sources(&canonical, &local, 0.0).unwrap();
        assert_eq!(result.stats.divergent_pixels, 1);
        assert_eq!(result.bootstrap.as_raw(), &[15, 30, 45, 255]);
        assert_eq!(result.divergence.as_raw(), &[30]);
    }

    #[test]
    fn threshold_keeps_canonical_when_delta_is_small() {
        let canonical = RgbaImage::from_raw(1, 1, vec![10, 20, 30, 255]).unwrap();
        let local = RgbaImage::from_raw(1, 1, vec![11, 21, 31, 255]).unwrap();
        let result = fold_sources(&canonical, &local, 0.01).unwrap();
        assert_eq!(result.stats.divergent_pixels, 0);
        assert_eq!(result.bootstrap.as_raw(), canonical.as_raw());
    }

    #[test]
    fn dimension_mismatch_is_rejected() {
        let canonical = RgbaImage::from_raw(1, 1, vec![10, 20, 30, 255]).unwrap();
        let local = RgbaImage::from_raw(2, 1, vec![10, 20, 30, 255, 10, 20, 30, 255]).unwrap();
        let error = fold_sources(&canonical, &local, 0.0).unwrap_err();
        assert!(error.contains("dimension mismatch"));
    }
}
